// 1. Grab the image URL (Source of Truth)
const imageUrl = $('Publish/Schedule Webhook').first().json.body.image_url;

let finalSubject = "";
let finalHtmlContent = "";
let isFallback = false;

try {
  // 2. PRIMARY: Attempt to Parse the Main LLM Output
  const rawText = $input.first().json.output[0].content[0].text;
  const cleanJsonString = rawText.replace(/```json|```/g, "").trim();
  const parsedData = JSON.parse(cleanJsonString);

  finalSubject = parsedData.subject;
  finalHtmlContent = parsedData.html_body;

} catch (e) {
  // 3. FALLBACK: If Main fails, pull from the 'Fallback Email Formatter' node
  isFallback = true;

  // Note: We use .first().json to get the pre-formatted fallback data
  const fallbackNode = $('Fallback Email Formatter').first().json;

  finalSubject = fallbackNode.subject || "Newsletter Update";
  // Check for 'html_body' first, then 'content' as a backup
  finalHtmlContent = fallbackNode.html_body || fallbackNode.content || "Content currently unavailable.";
}

/**
 * 4. Create the Clean Hero Image Component
 */
const imageHtml = `
  <div style="width: 100%; text-align: center; margin-top: 10px; margin-bottom: 35px;">
    <img src="${imageUrl}" 
         alt="Technical Insight" 
         style="width: 55%; max-width: 450px; height: auto; display: block; margin: 0 auto; border: none;"
    >
  </div>
`;

// 5. Prepend the image
const finalBody = imageHtml + finalHtmlContent;

// 6. Return the unified payload
return {
  subject: finalSubject,
  html_body: finalBody,
  source: isFallback ? 'FALLBACK' : 'PRIMARY',
  debug_info: isFallback ? "Main LLM output was malformed or missing." : "Success"
};

let finalContent = null;
let finalImagePrompt = "";
let finalUnsplashQuery = "";
let source = "PRIMARY";

// Helper to extract and parse JSON from a raw LLM string
function parseJsonFromText(rawText) {
  const clean = rawText.replace(/```json|```/g, "").trim();
  return JSON.parse(clean);
}

try {
  // PRIMARY PATH: OpenAI-style → output[0].content[0].text
  const rawText = $input.first().json.output[0].content[0].text;
  const parsed = parseJsonFromText(rawText);

  finalContent = parsed.content;
  finalImagePrompt = parsed.image_prompt;
  finalUnsplashQuery = parsed.unsplash_query;

} catch (primaryError) {
  try {
    // FALLBACK PATH: Gemini-style → content.parts[0].text
    source = "FALLBACK";
    const fallbackRaw = $input.first().json.content.parts[0].text;
    const parsed = parseJsonFromText(fallbackRaw);

    finalContent = parsed.content;
    finalImagePrompt = parsed.image_prompt;
    finalUnsplashQuery = parsed.unsplash_query;

  } catch (fallbackError) {
    // EMERGENCY: Both paths failed
    source = "ERROR_SYSTEM_FALLBACK";
    finalContent = ["System was unable to parse content from either source."];
    finalImagePrompt = "Abstract digital network background";
    finalUnsplashQuery = "technology";
  }
}

// n8n expects an array of items with a `json` key
return [{
  json: {
    content: finalContent,
    image_prompt: finalImagePrompt,
    unsplash_query: finalUnsplashQuery,
    source: source
  }
}];

