// 1. Capture the raw input
const input = $input.first().json;
let cleanContent = $('Clean Webhook Response Data').first().json.content;

// 2. LinkedIn Markdown Sanitizer
// Since LinkedIn doesn't support bold/italics, we strip them to keep it clean.
cleanContent = cleanContent
  .replace(/\*\*(.*?)\*\*/g, '$1') // Remove Bold **
  .replace(/\*(.*?)\*/g, '$1')     // Remove Italics *
  .replace(/###?\s+(.*)/g, '$1')   // Remove Headers #
  .trim();

// 3. Optional: Convert standard bullets to "Premium" Agency bullets
cleanContent = cleanContent.replace(/^[0-9]+\.\s/gm, '• '); 

// 4. Return the payload formatted for the LinkedIn Node
