={{
JSON.stringify({
  "from": "fetemi@updates.sakurasupport.live",
  "to": [ $json.fields.Email ],
  "subject": $('Clean Webhook Response Data').item.json.content.match(/^Subject:\s*(.*)$/mi)?.[1] || "New Update from Fetemi",
  "html": (function() {
    const name = ($json.fields.First_Name || "friend");
    let content = $('Clean Webhook Response Data').item.json.content;

    // 1. Remove the Subject line and the AI's "Hey there" to prevent double greeting
    content = content.replace(/^Subject:.*$/mi, "").replace(/^Hey there,.*$/mi, "").trim();

    // 2. Comprehensive Markdown to HTML conversion
    let formatted = content
      .replace(/^#### (.*$)/gm, '<h4 style="color: #333; margin: 20px 0 10px 0; font-family: sans-serif;">$1</h4>')
      .replace(/^### (.*$)/gm, '<h3 style="color: #1a1a1a; margin: 25px 0 10px 0; font-family: sans-serif;">$1</h3>')
      .replace(/^## (.*$)/gm, '<h2 style="color: #000; margin: 30px 0 15px 0; font-family: sans-serif; border-bottom: 1px solid #eee; padding-bottom: 5px;">$1</h2>')
      .replace(/\*\*(.*?)\*\*/g, '<b>$1</b>')
      .replace(/\[(.*?)\]\((.*?)\)/g, '<a href="$2" style="color: #d32f2f; text-decoration: underline; font-weight: bold;">$1</a>')
      .replace(/^[*-] (.*$)/gm, '<div style="margin-left: 20px; margin-bottom: 8px; color: #444;">• $1</div>')
      .replace(/\n/g, '<br>');

    // 3. The Branded Fetemi Template
    return `
      <div style="max-width: 600px; margin: 0 auto; font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; color: #333; line-height: 1.8; border: 1px solid #f0f0f0; border-radius: 12px; overflow: hidden; background-color: #ffffff;">
        <header style="padding: 30px; text-align: center; border-bottom: 1px solid #f9f9f9;">
          <img src="https://res.cloudinary.com/ptbysr/image/upload/v1774518191/Frame_3_2_bu4zjk.png" alt="Fetemi Marketing Agency" width="160" style="margin-bottom: 10px;">
          <p style="font-size: 10px; color: #bbb; letter-spacing: 2px; text-transform: uppercase; margin: 0;">Strategy • Growth • Execution</p>
        </header>
        <main style="padding: 40px 30px; background-color: #fafafa;">
          <p style="font-size: 16px; margin-bottom: 25px;">Hey ${name},</p>
          <div style="font-size: 15px; color: #444;">${formatted}</div>
        </main>
        <footer style="padding: 30px; text-align: center; font-size: 11px; color: #999; border-top: 1px solid #f0f0f0;">
          <p style="margin-bottom: 10px;">© 2026 Fetemi Marketing Agency. All rights reserved.</p>
          <p>You’re receiving this because you opted in to receive marketing insights from Paul and the Fetemi team.</p>
          <p style="margin-top: 15px;"><a href="https://fetemi.marketing/unsubscribe" style="color: #bbb; text-decoration: underline;">Unsubscribe</a></p>
        </footer>
      </div>
    `;
  })(),
  "headers": {
    "X-Request-ID": $('Clean Webhook Response Data').item.json.request_id
  }
})
}}

